// kumiko-feature-version: 1
//
// subscription-foundation als Kumiko bundled feature (Plugin-Host).
//
// **Multi-Provider von Tag 1** — der App-Builder kann mehrere Plugins
// parallel mounten (subscription-stripe + subscription-paypal +
// subscription-apple-iap + ...) und der Endkunde wählt beim Subscribe-
// Klick zwischen Karte/PayPal/Apple-Pay/Klarna/SEPA (Disney+-Pattern).
// KEIN globaler `provider`-config-key — alle gemounteten Plugins sind
// aktiv.
//
// **Was diese Foundation liefert:**
//   1. **Plugin-API** für Subscription-Provider via `r.extendsRegistrar(
//      "subscriptionProvider", ...)`.
//   2. **5 Domain-Events** auf dem `subscription`-stream (eine
//      stream-id pro Tenant): created/updated/canceled/invoice-paid/
//      invoice-payment-failed. Audit-history kommt frei vom event-store.
//   3. **Inline-Projection** auf `read_subscriptions` (= current state
//      pro Tenant). Apply läuft in derselben TX wie der event-append
//      → read-your-own-write semantics.
//   4. **process-event-handler**: programmatic write-handler den der
//      webhook-handler aufruft, dispatcht zu type-passendem appendEvent.
//   5. **createSubscriptionWebhookHandler**: factory für die HTTP-Route
//      `/api/subscription/webhook/:providerName`.
//
// **Was diese Foundation NICHT macht:**
//   - Kein r.entity für `subscription`. Die Tabelle ist eine reine
//     Read-Projection — kein CRUD-Pfad. Schreibt wird ausschließlich
//     via projection-apply, getriggert von einem der 5 events.
//   - Kein Tier-Sync zum tier-engine. App-Owner liest die subscription-
//     row via `getSubscriptionForTenant(ctx, tenantId)` wenn er möchte.
//   - Keine provider-spezifischen Configs.
//   - Kein Marketplace-Use-Case (App-Tenant billed Endkunden via
//     Stripe Connect). Kommt als separate `marketplace-foundation`.
//
// **Provider-Wechsel:** Disney+-Pattern (= Tenant cancelt Stripe-sub,
// startet neue mit PayPal) wird heute als zweiter `subscription-created`-
// event modelliert. UPSERT in der projection-apply überschreibt den
// existing row mit dem neuen providerName. Reicht für MVP. Wenn das
// business-fact "Provider-Wechsel" ein eigenes domain-event braucht
// (z.B. für analytics: "wie viele Wechsel im Monat?"), kommt ein
// `subscription-provider-changed`-event-type später.

import { defineFeature, type FeatureDefinition } from "@cosmicdrift/kumiko-framework/engine";
import { BILLING_FOUNDATION_FEATURE, SUBSCRIPTION_PROVIDER_EXTENSION } from "./constants";
import {
  INVOICE_PAID_EVENT_QN,
  INVOICE_PAID_EVENT_SHORT,
  INVOICE_PAYMENT_FAILED_EVENT_QN,
  INVOICE_PAYMENT_FAILED_EVENT_SHORT,
  SUBSCRIPTION_AGGREGATE_TYPE,
  SUBSCRIPTION_CANCELED_EVENT_QN,
  SUBSCRIPTION_CANCELED_EVENT_SHORT,
  SUBSCRIPTION_CREATED_EVENT_QN,
  SUBSCRIPTION_CREATED_EVENT_SHORT,
  SUBSCRIPTION_UPDATED_EVENT_QN,
  SUBSCRIPTION_UPDATED_EVENT_SHORT,
  subscriptionEventPayloadSchema,
} from "./events";
import { createCheckoutSessionHandler } from "./handlers/create-checkout-session.write";
import { createPortalSessionHandler } from "./handlers/create-portal-session.write";
import { listSubscriptionsQuery } from "./handlers/list-subscriptions.query";
import { processEventHandler } from "./handlers/process-event.write";
import {
  applyInvoicePaid,
  applyInvoicePaymentFailed,
  applySubscriptionCanceled,
  applySubscriptionCreated,
  applySubscriptionUpdated,
  subscriptionsProjectionTable,
} from "./projection";

export const billingFoundationFeature: FeatureDefinition = defineFeature(
  BILLING_FOUNDATION_FEATURE,
  (r) => {
    // 5 fine-grained domain-events. Alle 5 nutzen denselben payload-
    // shape (= subscription-state-snapshot); der event-type taggt was
    // passiert ist. Future-consumer (billing-history, accounting)
    // listenen direkt auf den event-type ohne payload-discriminator.
    r.defineEvent(SUBSCRIPTION_CREATED_EVENT_SHORT, subscriptionEventPayloadSchema);
    r.defineEvent(SUBSCRIPTION_UPDATED_EVENT_SHORT, subscriptionEventPayloadSchema);
    r.defineEvent(SUBSCRIPTION_CANCELED_EVENT_SHORT, subscriptionEventPayloadSchema);
    r.defineEvent(INVOICE_PAID_EVENT_SHORT, subscriptionEventPayloadSchema);
    r.defineEvent(INVOICE_PAYMENT_FAILED_EVENT_SHORT, subscriptionEventPayloadSchema);

    // Inline projection: materialized current state in `read_subscriptions`.
    // Apply läuft in derselben TX wie ctx.appendEventUnsafe — read-your-
    // own-write ohne dispatcher-tick.
    r.projection({
      name: "subscription",
      source: SUBSCRIPTION_AGGREGATE_TYPE,
      table: subscriptionsProjectionTable,
      apply: {
        [SUBSCRIPTION_CREATED_EVENT_QN]: applySubscriptionCreated,
        [SUBSCRIPTION_UPDATED_EVENT_QN]: applySubscriptionUpdated,
        [SUBSCRIPTION_CANCELED_EVENT_QN]: applySubscriptionCanceled,
        [INVOICE_PAID_EVENT_QN]: applyInvoicePaid,
        [INVOICE_PAYMENT_FAILED_EVENT_QN]: applyInvoicePaymentFailed,
      },
    });

    // Plugin extension-point. Provider-Plugins registrieren sich hier.
    r.extendsRegistrar(SUBSCRIPTION_PROVIDER_EXTENSION, {
      onRegister: () => {
        // No side-effects at register-time.
      },
    });

    // Custom write-handlers:
    //   - process-event: programmatic entry-point vom webhook-handler;
    //     dispatcht zu type-passendem appendEvent
    //   - create-checkout-session: Tenant-Admin "Upgrade to Pro"-flow
    //   - create-portal-session: Tenant-Admin "Manage Subscription"-flow
    r.writeHandler(processEventHandler);
    r.writeHandler(createCheckoutSessionHandler);
    r.writeHandler(createPortalSessionHandler);

    // Custom list-query auf der subscription-projection (raw drizzle-
    // table; kein r.entity weil Schreiben via projection-apply läuft).
    r.queryHandler(listSubscriptionsQuery);
  },
);

// cap-counter — Counter-Storage + Increment-API + Soft-Warn-State.
//
// **Was diese Feature liefert:**
//   1. r.entity("cap-counter") — Counter-Rows pro (tenant, capName,
//      period) für Calendar-Period-Caps (Mails/Monat, Egress/Monat).
//   2. increment-Handler — atomic counter increment via deterministic
//      aggregate-id (try-create / executor-update). Race-frei via
//      event-store optimistic-lock.
//   3. increment-rolling-Handler (Sprint 4) — append-only Custom-Event-
//      Stream für Rolling-Window-Caps (KI-Tokens-7d, Egress-24h). Kein
//      projection — der Wert kommt im Read aus dem Event-Stream.
//   4. mark-soft-warned-Handler — flippt das Anti-Notification-Storm-
//      Flag (nur Calendar-Period-Counter).
//   5. get-counter-Query — sync read der aktuellen Counter-Value
//      (Calendar).
//   6. enforceCap + enforceRollingCap-Helper (siehe enforce-cap.ts) —
//      Pre-Save-Wrapper mit asymmetrischen Soft/Hard-Toleranzen pro
//      Cap-Profile.
//
// **Calendar vs. Rolling — wann welches:**
//   - **Calendar-Period** (incrementCap + enforceCap): Cap resettet
//     sich am Period-Start (1. des Monats etc.). Counter ist 1 Row in
//     der projection. Schneller Read.
//   - **Rolling-Window** (incrementRollingCap + enforceRollingCap):
//     Cap rollt kontinuierlich (z.B. "letzten 7 Tage"). Werte
//     verfallen Event-für-Event ohne Reset. Kein projection — Read
//     summiert über die letzten N Tage Events.
//
// **Was diese Feature NICHT macht:**
//   - **Kein Foundation-Wiring.** mail-foundation / file-foundation /
//     ai-foundation sind heute BYOK-default und haben keinen Plattform-
//     Pool zum Zählen. Cap-Counter ist generic — wenn ein App-Owner
//     den Counter nutzen will, ruft er `incrementCap(...)` /
//     `incrementRollingCap(...)` aus seinem eigenen Handler auf.
//   - **Kein Reset-Cron für Calendar-Period.** Funktioniert ohne —
//     der periodStartIso-Bestandteil der aggregate-id rollt am
//     Period-Tick natürlich auf einen frischen Counter. Alte Rows
//     bleiben für Audit liegen.
//   - **Kein Notification-Pfad als Hard-Wiring.** Cap-counter
//     entkoppelt — `enforceCapAndMaybeNotify` (siehe enforce-cap.ts)
//     ist ein Convenience-Helper, der einen Caller-supplied
//     emit-Callback ausführt; cap-counter kennt delivery-feature
//     nicht direkt.
//
// **Boot-Dependencies:** keine. cap-counter ist Plain-Vanilla — kein
// config, kein secrets, kein tenant-feature nötig. Tenant-Scoping kommt
// vom Framework-Default (Base-Column tenantId).

import {
  defineEntityListHandler,
  defineFeature,
  type FeatureDefinition,
} from "@cosmicdrift/kumiko-framework/engine";
import { CAP_COUNTER_FEATURE, ROLLING_INCREMENTED_EVENT_SHORT } from "./constants";
import { capCounterEntity } from "./entity";
import { getCounterQuery } from "./handlers/get-counter.query";
import { incrementCapHandler } from "./handlers/increment.write";
import {
  incrementRollingCapHandler,
  rollingIncrementedSchema,
} from "./handlers/increment-rolling.write";
import { markSoftWarnedHandler } from "./handlers/mark-soft-warned.write";

const sysadminAccess = { access: { roles: ["SystemAdmin"] } } as const;

export const capCounterFeature: FeatureDefinition = defineFeature(CAP_COUNTER_FEATURE, (r) => {
  r.entity("cap-counter", capCounterEntity);

  // Custom Domain-Event für Rolling-Counter. r.defineEvent registriert
  // das Schema beim Registry; ctx.appendEventUnsafe im Handler nutzt
  // dasselbe Schema für Append-Time-Validation. QN nach Prefixing:
  // "cap-counter:event:rolling-incremented" (siehe
  // ROLLING_INCREMENTED_EVENT_QN).
  r.defineEvent(ROLLING_INCREMENTED_EVENT_SHORT, rollingIncrementedSchema);

  // Custom write-handlers.
  // - increment: Calendar-Period (CRUD via projection-row).
  // - increment-rolling: Rolling-Window (Custom-Event, no projection).
  // - mark-soft-warned: Anti-Notification-Storm-Flag (nur Calendar).
  r.writeHandler(incrementCapHandler);
  r.writeHandler(incrementRollingCapHandler);
  r.writeHandler(markSoftWarnedHandler);

  // Custom + standard reads. Sysadmin-cross-tenant via list, per-tenant
  // single-row via get-counter. Detail-by-id-handler bewusst weggelassen
  // (kein Use-Case; der natürliche Lookup ist über capName + period, nicht
  // über aggregate-id).
  r.queryHandler(defineEntityListHandler("cap-counter", capCounterEntity, sysadminAccess));
  r.queryHandler(getCounterQuery);
});

import { defineFeature, type FeatureDefinition } from "@cosmicdrift/kumiko-framework/engine";
import { createEmailChannel, type EmailChannelOptions } from "./email-channel";

export function createChannelEmailFeature(options: EmailChannelOptions): FeatureDefinition {
  const channel = createEmailChannel(options);

  return defineFeature("channelEmail", (r) => {
    r.requires("delivery");

    r.useExtension("deliveryChannel", "email", {
      resolve: channel.resolve,
      send: channel.send,
    });
  });
}

import { defineFeature, type FeatureDefinition } from "@cosmicdrift/kumiko-framework/engine";
import { inboxQuery } from "./handlers/inbox.query";
import { markAllReadWrite } from "./handlers/mark-all-read.write";
import { markReadWrite } from "./handlers/mark-read.write";
import { unreadCountQuery } from "./handlers/unread-count.query";
import { inAppChannel } from "./in-app-channel";

export function createChannelInAppFeature(): FeatureDefinition {
  return defineFeature("channelInApp", (r) => {
    r.requires("delivery");

    // Register as delivery channel via extension system
    r.useExtension("deliveryChannel", "inApp", {
      resolve: inAppChannel.resolve,
      send: inAppChannel.send,
    });

    const handlers = {
      markRead: r.writeHandler(markReadWrite),
      markAllRead: r.writeHandler(markAllReadWrite),
    };

    const queries = {
      inbox: r.queryHandler(inboxQuery),
      unreadCount: r.queryHandler(unreadCountQuery),
    };

    return { handlers, queries };
  });
}

import { defineFeature, type FeatureDefinition } from "@cosmicdrift/kumiko-framework/engine";
import { createPushChannel, type PushChannelOptions } from "./push-channel";

export function createChannelPushFeature(options: PushChannelOptions): FeatureDefinition {
  const channel = createPushChannel(options);

  return defineFeature("channelPush", (r) => {
    r.requires("delivery");

    r.useExtension("deliveryChannel", "push", {
      resolve: channel.resolve,
      send: channel.send,
    });
  });
}

import type { DbConnection, EncryptionProvider, TenantDb } from "@cosmicdrift/kumiko-framework/db";
import {
  type ConfigAccessor,
  type ConfigAccessorFactory,
  type ConfigKeyHandle,
  type ConfigKeyType,
  type ConfigValue,
  defineFeature,
  type FeatureDefinition,
  type HandlerContext,
  type Registry,
  type TenantId,
} from "@cosmicdrift/kumiko-framework/engine";
import { InternalError } from "@cosmicdrift/kumiko-framework/errors";
import { resetWrite } from "./handlers/reset.write";
import { schemaQuery } from "./handlers/schema.query";
import { setWrite } from "./handlers/set.write";
import { valuesQuery } from "./handlers/values.query";
import type { ConfigResolver } from "./resolver";
import { configValueEntity } from "./table";

export type ConfigContext = { readonly config: ConfigAccessor };

export function createConfigFeature(): FeatureDefinition {
  return defineFeature("config", (r) => {
    r.systemScope();

    // One aggregate stream per (key, scope) pair — the executor handles the
    // lifecycle events `configValue.created / .updated / .deleted` plus the
    // projection write in one TX. Subscribers that need config-change
    // semantics listen to those auto-events via r.multiStreamProjection
    // (see docs/plans/architecture/event-sourcing-pivot.md §4.7).
    r.entity("config-value", configValueEntity);

    const handlers = {
      set: r.writeHandler(setWrite),
      reset: r.writeHandler(resetWrite),
    };

    const queries = {
      values: r.queryHandler(valuesQuery),
      schema: r.queryHandler(schemaQuery),
    };

    return { handlers, queries };
  });
}

export function createConfigAccessor(
  registry: Registry,
  resolver: ConfigResolver,
  tenantId: TenantId,
  userId: string,
  db: DbConnection | TenantDb,
): ConfigAccessor {
  async function configAccessor(
    qualifiedKey: string,
  ): Promise<string | number | boolean | undefined>;
  async function configAccessor<T extends ConfigKeyType>(
    handle: ConfigKeyHandle<T>,
  ): Promise<ConfigValue<T> | undefined>;
  async function configAccessor(
    keyOrHandle: string | ConfigKeyHandle<ConfigKeyType>,
  ): Promise<string | number | boolean | undefined> {
    const qualifiedKey = typeof keyOrHandle === "string" ? keyOrHandle : keyOrHandle.name;
    const keyDef = registry.getConfigKey(qualifiedKey);
    if (!keyDef) return undefined;
    return resolver.get(qualifiedKey, keyDef, tenantId, userId, db);
  }
  return configAccessor;
}

// Pass to the test-stack / server-boot as `_configAccessorFactory` —
// `buildHandlerContext` mints a per-user `ctx.config` from this.
export function createConfigAccessorFactory(
  registry: Registry,
  resolver: ConfigResolver,
): ConfigAccessorFactory {
  return ({ user, db }) => createConfigAccessor(registry, resolver, user.tenantId, user.id, db);
}

// Single point of truth for "this handler needs the resolver". Throws a
// proper InternalError (with i18n) instead of bare Error, and points the
// caller at the boot wiring step that's missing — so a future debug
// session reads "config feature not wired into AppContext" instead of a
// generic "configResolver missing".
export function requireConfigResolver(ctx: HandlerContext, handlerName: string): ConfigResolver {
  if (!ctx.configResolver) {
    throw new InternalError({
      message:
        `[${handlerName}] ctx.configResolver missing — pass createConfigAccessorFactory's ` +
        `output via extraContext._configAccessorFactory and the resolver via ` +
        `extraContext.configResolver at boot.`,
    });
  }
  return ctx.configResolver;
}

// Mirror of requireConfigResolver for the encryption round-trip side.
// Only keys declared `encrypted: true` need this — the setter calls it
// lazily so apps that never wire encryption still boot (and only crash
// if a handler tries to write an encrypted key without the provider in
// place, pointing at the exact wiring gap).
export function requireConfigEncryption(
  ctx: HandlerContext,
  handlerName: string,
): EncryptionProvider {
  if (!ctx.configEncryption) {
    throw new InternalError({
      message:
        `[${handlerName}] ctx.configEncryption missing — at least one config key declares ` +
        `encrypted: true, so the boot wiring must pass an EncryptionProvider via ` +
        `extraContext.configEncryption (same instance the resolver was built with).`,
    });
  }
  return ctx.configEncryption;
}

