import { defineFeature, type FeatureDefinition } from "@cosmicdrift/kumiko-framework/engine";
import { cleanupJob } from "./handlers/cleanup.job";
import { listQuery } from "./handlers/list.query";
import { mineQuery } from "./handlers/mine.query";
import { revokeWrite } from "./handlers/revoke.write";
import { revokeAllOthersWrite } from "./handlers/revoke-all-others.write";
import { userSessionEntity } from "./schema/user-session";
import type { SessionMassRevoker } from "./session-callbacks";

export type SessionsFeatureOptions = {
  // When wired, a successful update on the `user` entity that changes the
  // `passwordHash` column triggers a mass-revoke of every live session for
  // that user. Industry-standard "password-change signs you out everywhere"
  // flow, including the session that did the change itself — the client has
  // to re-login after a password change.
  //
  // Runs as an afterCommit postSave hook: the password-change commits first,
  // then the sessions are revoked. Best-effort — if the mass-revoker throws,
  // the password change is NOT rolled back (a password change with a stale
  // session still wins over a user-visible error on the change itself).
  readonly autoRevokeOnPasswordChange?: SessionMassRevoker;
};

// The sessions feature registers the userSession entity and the three user-
// facing handlers (mine/revoke/revoke-all-others). It intentionally does NOT
// export a sessionCreator/sessionRevoker here — those are produced by
// `createSessionCallbacks()` at app-setup time and wired into
// `buildServer({ auth: { ... } })`.
//
// Why the split: handlers participate in the dispatcher pipeline (access
// checks, audit, hooks). The creator/revoker callbacks run on the hot
// login/request path and do direct-DB writes — threading them through the
// dispatcher would buy latency without added safety (the row columns ARE
// the audit trail).
//
// Not system-scoped: sessions live per tenant, and the handlers should only
// see rows in the caller's active tenant.
export function createSessionsFeature(options?: SessionsFeatureOptions): FeatureDefinition {
  return defineFeature("sessions", (r) => {
    r.entity("user-session", userSessionEntity);

    const handlers = {
      revoke: r.writeHandler(revokeWrite),
      revokeAllOthers: r.writeHandler(revokeAllOthersWrite),
    };

    const queries = {
      mine: r.queryHandler(mineQuery),
      list: r.queryHandler(listQuery),
    };

    // Retention: chunked DELETE of expired/revoked rows. Manual trigger
    // only so dev environments don't churn. Ops wires a cron in the app's
    // dispatcher config when running a long-lived deployment.
    r.job("cleanup", { trigger: { manual: true } }, cleanupJob);

    // Cross-feature entity hook on "user". `r.entityHook` (NOT `r.hook`) is
    // the supported cross-feature path: entity-keyed, not prefixed by the
    // registering feature. Fires after every successful write on any
    // user-entity handler; we only act when passwordHash is part of the
    // changes-delta the handler was given.
    //
    // Checking `changes["passwordHash"] !== undefined` is cheaper and more
    // correct than diffing data vs previous — "undefined in changes" means
    // "the handler didn't touch this column", which is exactly the signal
    // we want to skip on. Works for both direct user:update calls and any
    // other handler that happens to write the column.
    const autoRevoke = options?.autoRevokeOnPasswordChange;
    if (autoRevoke) {
      r.entityHook("postSave", "user", async (ctx) => {
        // skip: brand-new user, no sessions can possibly exist yet. The
        // initial passwordHash on a user:create would trip the second guard
        // otherwise — every registration would do a mass-revoke roundtrip
        // for a user who literally has no rows in user_sessions.
        if (ctx.isNew) return;
        // skip: handler didn't touch passwordHash, nothing to revoke
        if (ctx.changes["passwordHash"] === undefined) return;
        await autoRevoke(String(ctx.id));
      });
    }

    return { handlers, queries };
  });
}

// kumiko-feature-version: 1
//
// subscription-mollie — Mollie-Plugin für die subscription-foundation
// Plugin-API (EU-Compliance-Story für DACH-Mid-Market).
//
// **Factory-Pattern (analog subscription-stripe):** liest API-key beim
// mount-time aus den factory-options (typisch process.env aus dem App-
// Builder-bin/server.ts). Mollie hat KEIN webhook-secret — Mollie-SDK
// 4.5.0 bietet keine native HMAC-sig-verify-API. Sicherheit kommt aus
// nicht-guessable IDs + API-Validation; App-Builder kann optional
// einen URL-Token-Wrapper davor schalten.
//
// **Phase-5.3-Scope:**
//   - verifyAndParseWebhook ✓ (lazy-fetch payment + subscription via
//     Mollie-API, heuristisches event-type-mapping)
//   - createCheckoutSession ✓ (Mollie's mehrstufiger flow: customer
//     anlegen + first-payment mit sequenceType="first" → redirectUrl)
//   - createPortalSession ✗ (Mollie hat keinen Customer-Portal)
//   - cancelSubscription ✗ (Mollie braucht customerId zusätzlich zur
//     subId; Plugin-Contract reicht's nicht durch — App-Builder cancelt
//     via Mollie-Dashboard oder custom-route)
//
// **Beispiel-Verwendung in run-config.ts:**
//
//   const features = [
//     billingFoundationFeature,
//     createSubscriptionMollieFeature({
//       apiKey: process.env.MOLLIE_API_KEY ?? "",
//       webhookUrl: "https://app.example.com/api/subscription/webhook/mollie",
//       priceToTier: { plan_pro: "pro", plan_business: "business" },
//       priceToConfig: {
//         plan_pro: {
//           amountValue: "9.99",
//           amountCurrency: "EUR",
//           interval: "1 month",
//           description: "Pro-Abo monatlich",
//         },
//       },
//     }),
//   ];

import type { SubscriptionProviderPlugin } from "@cosmicdrift/kumiko-bundled-features/billing-foundation";
import { defineFeature, type FeatureDefinition } from "@cosmicdrift/kumiko-framework/engine";
import { createMollieClient } from "@mollie/api-client";
import { MOLLIE_PROVIDER_NAME, SUBSCRIPTION_MOLLIE_FEATURE } from "./constants";
import { createMollieCheckoutSession, type MolliePriceConfig } from "./plugin-methods";
import { type MollieClientShape, verifyAndParseMollieWebhook } from "./verify-webhook";

export type SubscriptionMollieOptions = {
  /** Mollie-API-key (`test_...` oder `live_...`). App-wide, beim Plugin-
   *  mount aus process.env oder system-config. */
  readonly apiKey: string;
  /** Foundation-webhook-URL die der App-Builder unter Mollie-Dashboard
   *  als webhook eingetragen hat. Plugin reicht das beim payment-
   *  create an Mollie weiter — Mollie sendet beim payment-event
   *  webhooks an diese URL. Typisch:
   *  `https://app.example.com/api/subscription/webhook/mollie`. */
  readonly webhookUrl: string;
  /** Price-to-tier-Map. Plugin liest die priceId aus dem subscription-
   *  metadata (= `metadata.priceId` den der App-Builder beim
   *  createCheckoutSession setzt) und mappt auf einen tier-name. */
  readonly priceToTier: Readonly<Record<string, string>>;
  /** Mollie-Subscription-Setup pro priceId. Mollie hat keinen nativen
   *  price-id-Konzept — App-Builder muss pro virtuellem priceId einen
   *  amount/interval/description bereitstellen. */
  readonly priceToConfig: Readonly<Record<string, MolliePriceConfig>>;
  /** @internal Test-only injection-port: ersetzt den verify-webhook-
   *  fetch-client durch eine Mock-instance. Production left undefined —
   *  factory baut den Adapter aus `createMollieClient(apiKey)`. Wird
   *  vom IT (mollie-foundation.integration.ts) genutzt damit der echte
   *  factory-Code (drift-validation, plugin-registration) im Test-pfad
   *  durchläuft, ohne dass Mollie-API-Calls passieren. */
  readonly _clientShapeForTests?: MollieClientShape;
};

export function createSubscriptionMollieFeature(
  options: SubscriptionMollieOptions,
): FeatureDefinition {
  if (options.apiKey.length === 0) {
    throw new Error(
      "subscription-mollie: apiKey is empty. Set MOLLIE_API_KEY (or system-config) before mounting.",
    );
  }
  if (options.webhookUrl.length === 0) {
    throw new Error(
      "subscription-mollie: webhookUrl is empty. Set the foundation-webhook-URL where Mollie sends events.",
    );
  }

  // Drift-Guard: priceToTier + priceToConfig müssen identische Keys
  // haben — sonst silent-null-returns aus verifyAndParseWebhook.
  const tierKeys = new Set(Object.keys(options.priceToTier));
  const configKeys = new Set(Object.keys(options.priceToConfig));
  const missingInConfig = [...tierKeys].filter((k) => !configKeys.has(k));
  const missingInTier = [...configKeys].filter((k) => !tierKeys.has(k));
  if (missingInConfig.length > 0 || missingInTier.length > 0) {
    throw new Error(
      `subscription-mollie: priceToTier ↔ priceToConfig drift — ` +
        `priceIds in tier but missing config: [${missingInConfig.join(", ")}]; ` +
        `priceIds in config but missing tier: [${missingInTier.join(", ")}]`,
    );
  }

  const client = createMollieClient({ apiKey: options.apiKey });

  // Adapter um den Plugin's verify-fetch-client an den vollen Mollie-
  // Client zu binden. Plugin-fetch-API ist minimal damit Tests ohne
  // den vollen MollieClient mocken können.
  const fetchAdapter: MollieClientShape = options._clientShapeForTests ?? {
    payments: { get: (id: string) => client.payments.get(id) },
    customerSubscriptions: {
      get: (subId: string, customerId: string) =>
        client.customerSubscriptions.get(subId, { customerId }),
      list: async (customerId: string) => {
        const page = await client.customerSubscriptions.page({ customerId });
        return [...page];
      },
      create: (customerId, params) =>
        client.customerSubscriptions.create({ customerId, ...params }),
    },
  };

  const verifyAndParse = verifyAndParseMollieWebhook(fetchAdapter, {
    priceToTier: options.priceToTier,
    priceToConfig: options.priceToConfig,
  });
  const checkoutSession = createMollieCheckoutSession(
    client,
    options.priceToConfig,
    options.webhookUrl,
  );

  return defineFeature(SUBSCRIPTION_MOLLIE_FEATURE, (r) => {
    r.requires("billing-foundation");

    const plugin: SubscriptionProviderPlugin = {
      verifyAndParseWebhook: verifyAndParse,
      createCheckoutSession: checkoutSession,
      // createPortalSession + cancelSubscription bewusst nicht — siehe
      // plugin-methods.ts für Begründung.
    };
    r.useExtension("subscriptionProvider", MOLLIE_PROVIDER_NAME, plugin);
  });
}

// kumiko-feature-version: 1
//
// subscription-stripe — Stripe-Plugin für die subscription-foundation
// Plugin-API.
//
// **Factory-Pattern (= createSubscriptionStripeFeature(options)):**
// Im Gegensatz zu mail-transport-smtp / file-provider-s3 (die ihre
// secrets aus tenant-secrets lesen) ist Stripe's webhook-secret
// **app-wide** — App-Owner hat einen Stripe-account, alle Webhooks
// gehen dorthin. Plugin braucht den secret beim webhook-sig-verify-
// Zeitpunkt, der ist PRE-tenant-resolution (kein ctx).
//
// Lösung: factory-Funktion `createSubscriptionStripeFeature(options)`
// liest webhook-secret + apiKey beim mount-time aus dem Caller (= App-
// Builder's bin/server.ts der's aus process.env zieht). Closure
// hält's für den verifyAndParseWebhook-call.
//
// Beispiel-Verwendung in run-config.ts:
//
//   import { createSubscriptionStripeFeature } from "@cosmicdrift/kumiko-bundled-features/subscription-stripe";
//
//   const features = [
//     billingFoundationFeature,
//     createSubscriptionStripeFeature({
//       webhookSecret: process.env.STRIPE_WEBHOOK_SECRET ?? "",
//       apiKey: process.env.STRIPE_API_KEY ?? "",
//       priceToTier: {
//         "price_1ABC": "pro",
//         "price_1XYZ": "business",
//       },
//     }),
//   ];
//
// **Pattern-Vorbild:** mirrors createFeatureTogglesFeature(options) —
// gleiche factory-Form für features die module-load-time-Konfiguration
// haben (analog zum FeatureToggle-runtime-holder).

import type { SubscriptionProviderPlugin } from "@cosmicdrift/kumiko-bundled-features/billing-foundation";
import { defineFeature, type FeatureDefinition } from "@cosmicdrift/kumiko-framework/engine";
import Stripe from "stripe";
import { STRIPE_PROVIDER_NAME, SUBSCRIPTION_STRIPE_FEATURE } from "./constants";
import {
  createStripeCancelSubscription,
  createStripeCheckoutSession,
  createStripePortalSession,
} from "./plugin-methods";
import { verifyAndParseStripeWebhook } from "./verify-webhook";

export type SubscriptionStripeOptions = {
  /** Webhook-secret aus dem Stripe-Dashboard. App-wide. Plugin throws
   *  beim runtime wenn empty (= App-Owner hat sub-stripe gemountet
   *  aber Stripe-Account nicht konfiguriert). */
  readonly webhookSecret: string;
  /** Stripe-API-key (sk_live_... / sk_test_...). Heute nur für
   *  constructEvent-API-Version-Pin gebraucht; Phase 5.2b nutzt's
   *  für outgoing-API-calls (createPortalSession etc.). */
  readonly apiKey: string;
  /** Price-to-tier-Mapping. Plugin liest die price-id aus Stripe-event
   *  (subscription.items.data[0].price.id) und mappt auf einen tier-
   *  name. Fehlt die price-id im Mapping → null (foundation 200
   *  ignored — App-Owner-Bug, hat den Stripe-price angelegt aber
   *  nicht zur tier zugeordnet). */
  readonly priceToTier: Readonly<Record<string, string>>;
};

/**
 * Factory für das subscription-stripe-feature. Wird mit den App-Owner-
 * eigenen Stripe-Credentials gemountet. Der returnte FeatureDefinition
 * registriert den Plugin gegen subscription-foundation's
 * "subscriptionProvider"-extension-point unter entityName "stripe".
 */
export function createSubscriptionStripeFeature(
  options: SubscriptionStripeOptions,
): FeatureDefinition {
  // Module-load-Validation: ohne webhook-secret kann der Plugin keinen
  // single Webhook verifizieren. Throw vor dem mount damit der App-
  // Owner nicht zur Laufzeit Mystery-401s sieht.
  if (options.webhookSecret.length === 0) {
    throw new Error(
      "subscription-stripe: webhookSecret is empty. Set STRIPE_WEBHOOK_SECRET (or system-config) before mounting.",
    );
  }
  if (options.apiKey.length === 0) {
    throw new Error(
      "subscription-stripe: apiKey is empty. Set STRIPE_API_KEY (or system-config) before mounting.",
    );
  }

  // EIN Stripe-Client für alle vier plugin-methods (verify-webhook +
  // checkout + portal + cancel). API-version-pin zentral, kein
  // Connection-Duplikat.
  const stripe = new Stripe(options.apiKey, { apiVersion: "2026-04-22.dahlia" });

  const verifyAndParse = verifyAndParseStripeWebhook(stripe, {
    webhookSecret: options.webhookSecret,
    priceToTier: options.priceToTier,
  });
  const checkoutSession = createStripeCheckoutSession(stripe);
  const portalSession = createStripePortalSession(stripe);
  const cancel = createStripeCancelSubscription(stripe);

  return defineFeature(SUBSCRIPTION_STRIPE_FEATURE, (r) => {
    // Hard-deps: subscription-foundation als plugin-host. KEIN
    // `r.requires("config", "secrets")` — der Plugin nutzt weder
    // tenant-config noch tenant-secrets (alles app-wide via factory-
    // options).
    r.requires("billing-foundation");

    // Plugin: register against subscription-foundation's
    // "subscriptionProvider" extension. entityName "stripe" matcht den
    // path-segment in der webhook-URL (`/api/subscription/webhook/stripe`).
    const plugin: SubscriptionProviderPlugin = {
      verifyAndParseWebhook: verifyAndParse,
      createCheckoutSession: checkoutSession,
      createPortalSession: portalSession,
      cancelSubscription: cancel,
    };
    r.useExtension("subscriptionProvider", STRIPE_PROVIDER_NAME, plugin);
  });
}

