import {
  access,
  createSystemConfig,
  createTenantConfig,
  defineFeature,
  type FeatureDefinition,
} from "@cosmicdrift/kumiko-framework/engine";
import { activeTenantIdsQuery } from "./handlers/active-tenant-ids.query";
import { addMemberWrite } from "./handlers/add-member.write";
import { cancelInvitationWrite } from "./handlers/cancel-invitation.write";
import { createWrite } from "./handlers/create.write";
import { disableWrite } from "./handlers/disable.write";
import { invitationsQuery } from "./handlers/invitations.query";
import { listQuery } from "./handlers/list.query";
import { meQuery } from "./handlers/me.query";
import { membersQuery } from "./handlers/members.query";
import { membershipsQuery } from "./handlers/memberships.query";
import { removeMemberWrite } from "./handlers/remove-member.write";
import { resolveUserIdsQuery } from "./handlers/resolve-user-ids.query";
import { updateWrite } from "./handlers/update.write";
import { updateMemberRolesWrite } from "./handlers/update-member-roles.write";
import { tenantInvitationEntity } from "./invitation-table";
import { tenantMembershipEntity } from "./membership-table";
import { tenantEntity } from "./schema/tenant";

export { tenantEntity, tenantTable } from "./schema/tenant";

// --- Feature ---

export function createTenantFeature(): FeatureDefinition {
  return defineFeature("tenant", (r) => {
    r.systemScope();
    r.requires("config");
    r.entity("tenant", tenantEntity);
    r.entity("tenant-membership", tenantMembershipEntity);
    r.entity("tenant-invitation", tenantInvitationEntity);

    r.config({
      keys: {
        // Stammdaten-Settings — Tenant-Admin darf ändern, alle dürfen lesen.
        companyName: createTenantConfig("text", { default: "" }),
        // Pragmatisch kuratierte Liste — IANA hat hunderte, hier die in der
        // Praxis relevantesten. Erweiterung später wenn echter Bedarf.
        timezone: createTenantConfig("select", {
          default: "Europe/Berlin",
          options: [
            "UTC",
            "Europe/Berlin",
            "Europe/London",
            "Europe/Paris",
            "Europe/Madrid",
            "Europe/Rome",
            "America/New_York",
            "America/Los_Angeles",
            "America/Sao_Paulo",
            "Asia/Tokyo",
            "Asia/Singapore",
            "Australia/Sydney",
          ],
        }),
        locale: createTenantConfig("select", {
          default: "de",
          options: ["de", "en", "fr", "es"],
        }),

        // SMTP — nur SystemAdmin (Plattform-Operator) ändert; smtpPass ist
        // verschlüsselt + nur für SystemAdmin lesbar.
        smtpHost: createTenantConfig("text", { write: access.systemAdmin, read: access.admin }),
        smtpPass: createTenantConfig("text", {
          write: access.systemAdmin,
          read: access.systemAdmin,
          encrypted: true,
        }),

        // System-Settings — nur programmatisch (SYSTEM_USER) änderbar,
        // Tenant-Admin sieht readonly.
        priceModel: createSystemConfig("select", {
          default: "basic",
          options: ["basic", "pro", "enterprise"],
        }),
        maxUsers: createSystemConfig("number", { default: 50 }),
      },
    });

    // Tenant CRUD
    const handlers = {
      create: r.writeHandler(createWrite),
      update: r.writeHandler(updateWrite),
      disable: r.writeHandler(disableWrite),
      addMember: r.writeHandler(addMemberWrite),
      removeMember: r.writeHandler(removeMemberWrite),
      updateMemberRoles: r.writeHandler(updateMemberRolesWrite),
      cancelInvitation: r.writeHandler(cancelInvitationWrite),
    };

    // Queries
    const queries = {
      me: r.queryHandler(meQuery),
      list: r.queryHandler(listQuery),
      memberships: r.queryHandler(membershipsQuery),
      members: r.queryHandler(membersQuery),
      activeTenantIds: r.queryHandler(activeTenantIdsQuery),
      resolveUserIds: r.queryHandler(resolveUserIdsQuery),
      invitations: r.queryHandler(invitationsQuery),
    };

    return { handlers, queries };
  });
}

import { defineFeature, type FeatureDefinition } from "@cosmicdrift/kumiko-framework/engine";
import { bySlugQuery } from "./handlers/by-slug.query";
import { setWrite } from "./handlers/set.write";
import { textBlockEntity } from "./table";

// text-content — generischer Container für statische Texte (Impressum,
// Datenschutz, FAQ, About, ToS, Marketing-Snippets). Pro
// (tenantId, slug, lang) genau ein Block. Inhalt ist Markdown — die
// Konvertierung zu HTML übernehmen Consumer-Features wie legal-pages
// (das opt-in obendrauf-Feature für Compliance-Pages).
//
// Opt-in: wer keine statischen Texte braucht (interne Tools), aktiviert
// das Feature gar nicht. Wer es aktiviert, hat sofort CRUD + by-slug-
// query — Routes/Render kommen pro Use-Case (legal-pages, etc.).
export function createTextContentFeature(): FeatureDefinition {
  return defineFeature("text-content", (r) => {
    r.entity("text-block", textBlockEntity);

    const handlers = {
      set: r.writeHandler(setWrite),
    };

    const queries = {
      bySlug: r.queryHandler(bySlugQuery),
    };

    return { handlers, queries };
  });
}

// tier-engine — Pricing-Tier-Mechanik als reguläres Bundled-Feature.
//
// **Was diese Feature macht:**
//   Speichert pro Plattform-Tenant ein Tier-Assignment (welcher Tier ist
//   aktiv). composeApp-Helper liest diesen Stand und leitet daraus ab,
//   welche Features für den Tenant gemountet werden.
//
// **Generic über Tier-Werte:** das Feature kennt keine "free"/"pro"/etc.
//   konkreten Tier-Werte. Es speichert nur den Tier-Namen als String. Die
//   App definiert ihre TierMap (siehe compose-app.ts), damit kumiko.so,
//   PublicStatus, und andere Kumiko-Apps je eigene Tier-Sets nutzen können.
//
// **Standard-CRUD-Handler in Sprint 1:** Create/Update/List/Detail per
//   `defineEntityXxxHandler`. Idempotente set-tier-Logic (deterministic
//   aggregate-id, create-or-update-Routing) kommt im stripe-sync-Feature
//   in Sprint 5 als Wrapper darum.
//
// **Tenant-Scope:** tier-engine ist tenant-scoped. Plattform-Tenant verwaltet
//   seinen eigenen Tier (Self-Service-Upgrade-UI). Stripe-Webhook (Sprint 5)
//   wird im stripe-sync-Feature die tenant-resolution machen und den
//   tier-assignment:create/update-Handler mit dem aufgelösten Context
//   aufrufen.
//
// **Was Sprint 1 NICHT macht:**
//   - Custom Domain-Events (`tier-changed`) — emittiert werden derzeit nur
//     die CRUD-Auto-Events. Sprint 4 (Add-On-Marketplace) erweitert das auf
//     semantische Domain-Events.
//   - Add-Ons im Schema — Sprint 4 fügt sie als separate
//     `tier-add-on`-Entity hinzu (1:n Relation, ES-saubere Add/Remove-Events).
//   - Cap-Counter-Integration — kommt mit `cap-counter`-Feature in Sprint 3.
//   - Stripe-Sync + Idempotent-Set-Tier-Wrapper — kommt mit `stripe-sync`-
//     Feature in Sprint 5.
//
// **Boot-Dependencies:**
//   r.requires("config") — transitiv für tenant.
//   r.requires("tenant") — tier-assignment lebt im Plattform-Tenant-Kontext.

import {
  defineEntityCreateHandler,
  defineEntityListHandler,
  defineEntityUpdateHandler,
  defineFeature,
  type FeatureDefinition,
} from "@cosmicdrift/kumiko-framework/engine";
import { TIER_ENGINE_FEATURE } from "./constants";
import { tierAssignmentEntity } from "./entity";
import { getActiveTierQuery } from "./handlers/active-tier.query";

const adminAccess = { access: { roles: ["TenantAdmin", "SystemAdmin"] } } as const;

export const tierEngineFeature: FeatureDefinition = defineFeature(TIER_ENGINE_FEATURE, (r) => {
  r.requires("config");
  r.requires("tenant");

  r.entity("tier-assignment", tierAssignmentEntity);

  // Standard-CRUD via Helper. Sprint 5 wraps these in a custom set-tier
  // handler with deterministic aggregate-id for Stripe-Webhook idempotency.
  r.writeHandler(defineEntityCreateHandler("tier-assignment", tierAssignmentEntity, adminAccess));
  r.writeHandler(defineEntityUpdateHandler("tier-assignment", tierAssignmentEntity, adminAccess));

  // Reads.
  //   - list: cross-tenant view for SystemAdmin (debug/migration-tooling)
  //     and per-tenant 0-or-1-row view for TenantAdmin (auto-tenant-scoped)
  //   - get-active-tier: convenience-wrapper for the only sensible per-tenant
  //     query — returns the single row or null. composeApp consumes this.
  //
  // Detail-by-id-handler bewusst weggelassen — kein Use-Case, weil pro Tenant
  // genau eine Row existiert; get-active-tier ist die richtige Lookup-Form.
  r.queryHandler(defineEntityListHandler("tier-assignment", tierAssignmentEntity, adminAccess));
  r.queryHandler(getActiveTierQuery);
});

import { defineFeature, type FeatureDefinition } from "@cosmicdrift/kumiko-framework/engine";
import { createWrite } from "./handlers/create.write";
import { detailQuery } from "./handlers/detail.query";
import { findForAuthQuery } from "./handlers/find-for-auth.query";
import { listQuery } from "./handlers/list.query";
import { meQuery } from "./handlers/me.query";
import { updateWrite } from "./handlers/update.write";
import { userEntity } from "./schema/user";

// The user feature holds the cross-tenant user identity. `systemScope()` means
// queries and writes bypass the tenant filter — a user exists above any tenant.
// Membership + tenant-specific roles live in the tenant feature.
export function createUserFeature(): FeatureDefinition {
  return defineFeature("user", (r) => {
    r.systemScope();
    r.entity("user", userEntity);

    const handlers = {
      create: r.writeHandler(createWrite),
      update: r.writeHandler(updateWrite),
    };

    const queries = {
      me: r.queryHandler(meQuery),
      detail: r.queryHandler(detailQuery),
      list: r.queryHandler(listQuery),
      findForAuth: r.queryHandler(findForAuthQuery),
    };

    return { handlers, queries };
  });
}

