// Lane-Routing Sample
//
// Shows `r.job({ runIn: "worker" })` end-to-end: an HTTP write emits an
// event, the event fans out to two worker-lane jobs via BullMQ, and the
// jobs actually execute on the worker lane (kumiko-jobs-worker queue).
//
// Deploy-shape: any of the three entrypoints. The test uses
// createAllInOneEntrypoint so the Single Integration-Test covers the full
// path without having to coordinate two processes.

import {
  createEntity,
  createNumberField,
  createTextField,
  defineFeature,
  type FeatureDefinition,
} from "@cosmicdrift/kumiko-framework/engine";
import { z } from "zod";

// In-memory collectors so the integration-test can assert both jobs ran
// and got the right payload. A real app would do DB writes, HTTP calls,
// PDF rendering, mail sending — whatever the side-effect is, it's
// opaque to the framework.
export const renderedReceipts: Array<{ customerName: string; amount: number }> = [];
export const sentConfirmations: Array<{ customerName: string; amount: number }> = [];

// Entity-Dekl sichert den qualified-name-Prefix "orders:write:order:create"
// für den Write-Handler unten und damit den Job-Trigger auf diesem Event.
// Persistenz passiert im Custom-Handler nicht (id ist hardcoded für den
// Sample-Test) — in einer echten App würde ein entityWriteHandler in die DB
// schreiben.
const orderEntity = createEntity({
  table: "read_orders",
  fields: {
    customerName: createTextField({ required: true }),
    amount: createNumberField({ required: true }),
  },
});

export function createLaneRoutingFeature(): FeatureDefinition {
  return defineFeature("orders", (r) => {
    r.entity("order", orderEntity);

    // Write handler — runs in the API process (or wherever the command
    // lands). Event "orders:write:order:create" is the auto-generated
    // write-event both jobs trigger on.
    r.writeHandler(
      "order:create",
      z.object({
        customerName: z.string().min(1),
        amount: z.number().positive(),
      }),
      async (event) => ({
        isSuccess: true as const,
        data: {
          id: 1,
          customerName: event.payload.customerName,
          amount: event.payload.amount,
        },
      }),
      { access: { openToAll: true } },
    );

    // Receipt-rendering: heavy CPU work. Pinned to `worker` so the
    // BullMQ consumer on the API process never picks it up — even if the
    // API happens to run runLocalJobs for something else. `runIn` is the
    // Welle-2.6 contract that makes this stable across deploy shapes.
    r.job(
      "render-receipt",
      {
        trigger: { on: "orders:write:order:create" },
        runIn: "worker",
      },
      async (payload) => {
        renderedReceipts.push({
          customerName: payload["customerName"] as string,
          amount: payload["amount"] as number,
        });
      },
    );

    // Confirmation-mail: external I/O. Also worker-lane. Both jobs fan
    // out from the same event in parallel — BullMQ handles their order
    // independently.
    r.job(
      "send-confirmation",
      {
        trigger: { on: "orders:write:order:create" },
        runIn: "worker",
      },
      async (payload) => {
        sentConfirmations.push({
          customerName: payload["customerName"] as string,
          amount: payload["amount"] as number,
        });
      },
    );
  });
}

// Legal-Pages Sample
//
// DACH-Apps (DE/AT/CH) sind verpflichtet ein Impressum (TMG/DDG §5) und
// eine Datenschutzerklärung (DSGVO Art. 13) öffentlich zugänglich zu
// haben. Das ist 1) für jede App identisch und 2) nervig manuell pro
// App neu zu basteln.
//
// Lösung: zwei opt-in bundled-features kombinieren:
//
//  - `text-content`  — generischer Markdown-Text-Container (Entity
//    `text-block` mit slug+lang+title+body, scoped per Tenant). Auch
//    nutzbar für FAQ, About, ToS, Marketing-Snippets — nicht
//    legal-spezifisch.
//
//  - `legal-pages`   — opt-in-Wrapper darauf, der vier feste Public-
//    Routes (`/legal/impressum`, `/legal/datenschutz`, `/legal/imprint`,
//    `/legal/privacy`) registriert und Markdown→HTML rendered. Plus
//    Boot-Check der in Production hart fehlt wenn die DE-Pflicht-Blocks
//    fehlen.
//
// Tenant-Modell: 1 App = X Tenants = 1 Impressum. Alle Subdomains
// teilen sich die SYSTEM_TENANT_ID-Version. Wer pro-Tenant-Impressums
// braucht, muss sein eigenes Routing davorsetzen oder die text-content-
// query mit tenant-specific tenantId nutzen.
//
// Voraussetzungen für Production:
//  - `anonymousAccess` muss in runProdApp/runDevApp konfiguriert sein
//    (defaultTenantId = SYSTEM_TENANT_ID), sonst antworten die
//    legal-pages-Routes mit 503
//  - `extraContext.textContent = createTextContentApi(db)` muss gewired
//    sein, sonst wirft der Boot-Check mit Wiring-Hinweis
//  - Beim ersten Boot müssen die TextBlocks geseedet sein —
//    text-content/seeding `seedTextBlock` oder via API
//    `text-content:write:set` mit TenantAdmin-Token

import {
  createLegalPagesFeature,
  LEGAL_REQUIRED_BLOCKS,
  LEGAL_ROUTES,
} from "@cosmicdrift/kumiko-bundled-features/legal-pages";
import { createTextContentFeature } from "@cosmicdrift/kumiko-bundled-features/text-content";

// Beide Features aktivieren — text-content ist Foundation, legal-pages
// requires sie. r.requires("text-content") greift automatisch im
// legal-pages-Feature.
export const textContentFeature = createTextContentFeature();
export const legalPagesFeature = createLegalPagesFeature();

// Re-exports für Tests + andere Demos
export { LEGAL_REQUIRED_BLOCKS, LEGAL_ROUTES };

