// Lifecycle Hooks Sample
// Shows: validation hooks (reject bad data), postSave entity hooks (track changes),
// preDelete hooks (block delete on invariant violation), postDelete hooks
// (log deletions after commit).

import {
  createBooleanField,
  createEntity,
  createTextField,
  defineEntityCreateHandler,
  defineEntityDeleteHandler,
  defineEntityUpdateHandler,
  defineFeature,
  type SaveContext,
} from "@cosmicdrift/kumiko-framework/engine";
import { ConflictError } from "@cosmicdrift/kumiko-framework/errors";

export const articleEntity = createEntity({
  table: "read_sample_articles",
  fields: {
    // maxLength high so zod lets long titles through — the validation hook
    // below rejects titles > 200 so the sample can demonstrate the hook path.
    title: createTextField({ required: true, maxLength: 1000 }),
    content: createTextField(),
    status: createTextField({ default: "draft" }),
    isPublished: createBooleanField({ default: false }),
  },
});

// Collect hook events for testing
export const hookLog: { type: string; data: Record<string, unknown> }[] = [];

const editorWrite = { access: { roles: ["Admin", "Editor"] } } as const;

export const articlesFeature = defineFeature("blog", (r) => {
  const article = r.entity("article", articleEntity);

  const articleCreate = r.writeHandler(
    defineEntityCreateHandler("article", articleEntity, editorWrite),
  );
  const articleUpdate = r.writeHandler(
    defineEntityUpdateHandler("article", articleEntity, editorWrite),
  );
  r.writeHandler(defineEntityDeleteHandler("article", articleEntity, editorWrite));

  // --- Validation hook on create: reject banned words + length ---
  r.hook("validation", articleCreate, (data) => {
    const title = data["title"] as string;
    if (title.toLowerCase().includes("spam")) {
      return [{ field: "title", error: "title_contains_banned_word" }];
    }
    if (title.length > 200) {
      return [{ field: "title", error: "title_too_long" }];
    }
    return null;
  });

  // --- Validation hook on update: length check on title changes ---
  r.hook("validation", articleUpdate, (data) => {
    const changes = data["changes"] as Record<string, unknown> | undefined;
    const title = changes?.["title"] as string | undefined;
    if (title && title.length > 200) {
      return [{ field: "title", error: "title_too_long" }];
    }
    return null;
  });

  // --- postSave entity hook: log all saves ---
  r.entityHook("postSave", article, async (result: SaveContext) => {
    hookLog.push({
      type: result.isNew ? "created" : "updated",
      data: { id: result.id, changes: result.changes },
    });
  });

  // --- preDelete entity hook: block delete when the article is still published.
  // preDelete runs inside the write transaction and throws on violation, so
  // the delete rolls back before any projection or event is written. The
  // payload.data carries the full row snapshot taken just before delete —
  // no extra load needed.
  r.entityHook("preDelete", article, async (payload) => {
    if (payload.data["isPublished"] === true) {
      throw new ConflictError({
        message: `article ${payload.id} is still published`,
        i18nKey: "errors.publishedArticleCannotBeDeleted",
        details: { reason: "published_article_cannot_be_deleted", entityId: payload.id },
      });
    }
  });

  // --- postDelete entity hook: log deletions after the transaction commits.
  // Default phase is afterCommit so failures here can't roll back the delete.
  r.entityHook("postDelete", article, async (payload) => {
    hookLog.push({
      type: "deleted",
      data: { id: payload.id },
    });
  });
});

// Ownership Sample
//
// Concrete contract-entity showing the full ownership matrix:
//
//   Dimension      | Entity-level         | Field-level
//   -----------    | -------------------- | --------------------------------
//   Read           | list/detail filter   | propX stripped from response JSON
//   Write          | create/update/delete | individual fields rejected loud
//   Rule shape     | { Role: OwnershipRule }            (same on both dimensions)
//   Rule kinds     | "all" | from(ref, col?) | { where: (user, table) => SQL }
//
// The entity below is the "contract" example from the H.2 design
// discussion: propA is public, propB is Admin-only, propC requires a
// matching team claim. Integration tests prove each row/column path.
//
// Why fail-loud on write (not silent drop): Silent-drop makes bugs
// invisible at the reporting layer. "Save doesn't work" with no error
// becomes weeks of blame between frontend / API / infrastructure. A loud
// `field_ownership_denied` with the field name + role + userId in the
// details payload is a single log-line to a root cause.

import {
  createEntity,
  createTextField,
  defineEntityCreateHandler,
  defineEntityDeleteHandler,
  defineEntityDetailHandler,
  defineEntityListHandler,
  defineEntityRestoreHandler,
  defineEntityUpdateHandler,
  defineFeature,
  from,
} from "@cosmicdrift/kumiko-framework/engine";

// The "teams" feature declares the teamId claim. Any other feature can
// reference it via the QN string "teams:teamId" in ownership rules — no
// cross-feature import needed. The boot-validator rejects a reference to a
// claim no feature declared.
export const teamsFeature = defineFeature("teams", (r) => {
  r.claimKey("teamId", { type: "string" });
});

// Contract entity demonstrating the full access matrix.
export const contractEntity = createEntity({
  table: "read_ownership_contracts",
  softDelete: true,
  fields: {
    // teamId is the ownership-scoping column. It's referenced by claim-rules
    // via the default column (rule's shortName = "teamId" matches).
    teamId: createTextField({ required: true }),
    // Optional — when set, only that user (via user:id rule) can access.
    assigneeId: createTextField(),

    // propA: public field. No access declared — every caller reads AND writes.
    propA: createTextField(),

    // propB: Admin-only. Non-admins don't see it in responses; attempts
    // to write it return access_denied (role gate in dispatcher).
    propB: createTextField({
      access: {
        read: { Admin: "all" },
        write: { Admin: "all" },
      },
    }),

    // propC: Admin + Matching-Team. Non-admins with the wrong team see no
    // propC in responses; writes to propC on a foreign team's row return
    // field_ownership_denied (executor ownership check).
    propC: createTextField({
      access: {
        read: { Admin: "all", TeamMember: from("claim:teams:teamId") },
        write: { Admin: "all", TeamMember: from("claim:teams:teamId") },
      },
    }),
  },

  // Entity-level access: controls list/detail/update/delete/restore of the
  // whole row. Admin sees everything; TeamMember scoped to their team;
  // assigned Driver sees rows assigned to them.
  access: {
    read: {
      Admin: "all",
      TeamMember: from("claim:teams:teamId"),
      Driver: from("user:id", "assigneeId"),
    },
    write: {
      Admin: "all",
      TeamMember: from("claim:teams:teamId"),
      Driver: from("user:id", "assigneeId"),
    },
  },
});

export const contractsFeature = defineFeature("contracts", (r) => {
  r.entity("contract", contractEntity);

  r.writeHandler(
    defineEntityCreateHandler("contract", contractEntity, {
      access: { roles: ["Admin", "TeamMember", "Driver"] },
    }),
  );
  r.writeHandler(
    defineEntityUpdateHandler("contract", contractEntity, {
      access: { roles: ["Admin", "TeamMember", "Driver"] },
    }),
  );
  r.writeHandler(
    defineEntityDeleteHandler("contract", contractEntity, {
      access: { roles: ["Admin", "TeamMember", "Driver"] },
    }),
  );
  r.writeHandler(
    defineEntityRestoreHandler("contract", contractEntity, {
      access: { roles: ["Admin", "TeamMember", "Driver"] },
    }),
  );
  r.queryHandler(
    defineEntityListHandler("contract", contractEntity, {
      access: { roles: ["Admin", "TeamMember", "Driver"] },
    }),
  );
  r.queryHandler(
    defineEntityDetailHandler("contract", contractEntity, {
      access: { roles: ["Admin", "TeamMember", "Driver"] },
    }),
  );
});

