// Rate-Limiting Showcase — minimal feature
//
// Declares one query handler with an L3 rateLimit option so the
// dispatcher gates calls before the handler body runs. The integration
// test pairs this with L1+L2 middleware wired via buildServer's
// `rateLimit` option to prove all three layers stack.

import { defineFeature, type FeatureDefinition } from "@cosmicdrift/kumiko-framework/engine";
import { z } from "zod";

export function createRateLimitShowcaseFeature(): FeatureDefinition {
  return defineFeature("rl-showcase", (r) => {
    // Per-user budget. Real apps tune `limit` to actual handler cost — a
    // search call against a sharded index might warrant 5/min, a full
    // export 1/min. The bucket is `user:<userId>` (see rate-limit/bucket.ts).
    r.queryHandler(
      "expensive-search",
      z.object({ q: z.string().min(1) }),
      async ({ payload }) => ({ q: payload.q, hits: 0 }),
      {
        access: { roles: ["Admin", "User"] },
        rateLimit: { per: "user", limit: 3, windowSeconds: 60 },
      },
    );
  });
}

// Realtime SSE Sample
// Shows: SSE broadcast on create/update/delete via system hook.

import {
  createEntity,
  createTextField,
  defineEntityCreateHandler,
  defineEntityDeleteHandler,
  defineEntityUpdateHandler,
  defineFeature,
} from "@cosmicdrift/kumiko-framework/engine";

export const messageEntity = createEntity({
  table: "read_sample_messages",
  fields: {
    channel: createTextField({ required: true }),
    text: createTextField({ required: true }),
    author: createTextField(),
  },
  softDelete: true,
});

const userWrite = { access: { roles: ["Admin", "User"] } } as const;
const adminWrite = { access: { roles: ["Admin"] } } as const;

export const chatFeature = defineFeature("chat", (r) => {
  r.entity("message", messageEntity);

  r.writeHandler(defineEntityCreateHandler("message", messageEntity, userWrite));
  r.writeHandler(defineEntityUpdateHandler("message", messageEntity, userWrite));
  r.writeHandler(defineEntityDeleteHandler("message", messageEntity, adminWrite));
});

// Reference Data Sample
// Shows: r.referenceData() for static seed data with upsert logic

import { table, text } from "@cosmicdrift/kumiko-framework/db";
import { createEntity, createTextField, defineFeature } from "@cosmicdrift/kumiko-framework/engine";

export const categoryEntity = createEntity({
  table: "read_sample_categories",
  fields: {
    code: createTextField({ required: true }),
    name: createTextField({ required: true }),
    description: createTextField(),
  },
});

// Drizzle table for direct DB queries in tests
export const categoryTable = table("read_sample_categories", {
  code: text("code").notNull(),
  name: text("name").notNull(),
  description: text("description"),
});

export const categoryFeature = defineFeature("catalog", (r) => {
  r.entity("category", categoryEntity);

  // Static reference data — seeded on boot, upserted on changes
  r.referenceData(
    "category",
    [
      { code: "electronics", name: "Electronics", description: "Phones, laptops, tablets" },
      { code: "clothing", name: "Clothing", description: "Shirts, pants, shoes" },
      { code: "books", name: "Books", description: "Fiction and non-fiction" },
      { code: "food", name: "Food & Drinks", description: "Groceries and beverages" },
    ],
    { upsertKey: "code" },
  );
});

// Relations Sample
// Shows: hasMany relation, onDelete: cascade vs restrict, parent-child entities.

import { buildDrizzleTable } from "@cosmicdrift/kumiko-framework/db";
import {
  createEntity,
  createTextField,
  defineEntityCreateHandler,
  defineEntityDetailHandler,
  defineFeature,
} from "@cosmicdrift/kumiko-framework/engine";

export const teamEntity = createEntity({
  table: "read_sample_teams",
  fields: {
    name: createTextField({ required: true }),
  },
});

export const memberEntity = createEntity({
  table: "read_sample_members",
  fields: {
    name: createTextField({ required: true }),
    // UUID foreign keys are stored as text columns so the string UUID fits.
    teamId: createTextField({ required: true }),
    role: createTextField(),
  },
});

export const taskEntity = createEntity({
  table: "read_sample_member_tasks",
  fields: {
    title: createTextField({ required: true }),
    memberId: createTextField({ required: true }),
  },
});

// Tables exported so the integration test can wire the cascade-delete hook.
export const teamTable = buildDrizzleTable("team", teamEntity);
export const memberTable = buildDrizzleTable("member", memberEntity);
export const taskTable = buildDrizzleTable("task", taskEntity);

const adminWrite = { access: { roles: ["Admin"] } } as const;
const openRead = { access: { openToAll: true } } as const;

export const relationsFeature = defineFeature("org", (r) => {
  const team = r.entity("team", teamEntity);
  const member = r.entity("member", memberEntity);
  r.entity("task", taskEntity);

  // Team has many members — restrict delete when members exist.
  r.relation(team, "members", {
    type: "hasMany",
    target: "member",
    foreignKey: "teamId",
    onDelete: "restrict",
  });

  // Member has many tasks — cascade delete tasks when member is deleted.
  r.relation(member, "tasks", {
    type: "hasMany",
    target: "task",
    foreignKey: "memberId",
    onDelete: "cascade",
  });

  r.writeHandler(defineEntityCreateHandler("team", teamEntity, adminWrite));
  r.writeHandler(defineEntityCreateHandler("member", memberEntity, adminWrite));
  r.writeHandler(defineEntityCreateHandler("task", taskEntity, adminWrite));
  r.queryHandler(defineEntityDetailHandler("task", taskEntity, openRead));
});

